import numpy as np

class GameBoard:
    def __init__(self):
        self.board = np.zeros((8, 8), dtype=int)
        self.setup_board()

    def setup_board(self):
        for i in range(3):
            for j in (1, 3, 5, 7):
                if (i + j) % 2 == 1:
                    self.board[i, j] = -1
        for i in range(5, 8):
            for j in (0, 2, 4, 6):
                if (i + j) % 2 == 1:
                    self.board[i, j] = 1

    def display(self):
        print(self.board)
```

